        duration: bounds.statusVocabulary.durationTurns.poison.min - 1
      })
    ],
    [
      "cure_status",
      makeEffectFixture("cure_status", "cureStatus", {
        status: "not-a-status"
      } as unknown as NonNullable<Effect["cureStatus"]>)
    ],
    [
      "buff_stat",
      makeEffectFixture("buff_stat", "buffStat", {
